import heapq

def hopcroft_karp(A, B):
    # Initialize the matching and the augmenting path
    matching = {}
    augmenting_path = [[]]

    # Find an augmenting path for each pair of edges in both directions
    while augmenting_path:
        next_edge_A = None
        next_edge_B = None

        # Check if removing an edge from A would increase the size of the current matching
        for edge in aug_list_A:
            if edge[0] not in matching and edge[1] in matching.values():
                return len(matching)

            if edge[1] not in matching and edge[0] in matching.values():
                return len(matching)

        # If no augmenting path is found, remove the last added edge
        removed_edge_A = augmenting_path.pop()

        # Update the priority queue with new edges that are still potential augmenting edges
        aug_list_B = []
        for edge in B:
            if edge[1] not in matching.values() and edge[0] in matching.keys():
                aug_list_B.append(edge)

        # Check if removing an edge from B would increase the size of the current matching
        for edge in aug_list_B:
            if edge[0] not in matching and edge[1] in matching.values():
                return len(matching)

            if edge[1] not in matching and edge[0] in matching.values():
                return len(matching)

        # Add the removed edge to the augmenting path
        if next_edge_A:
            augmented_edges = [edge for edge in aug_list_B if edge != next_edge_A]
            if augmented_edges:
                new_matching = {**matching, **augmented_edges}
                yield max(new_matching, key=match)
        else:
            # Update the matching and add a new edge
            match = max(matching, key=match)
            new_matching = {**match, **{edge[1]: edge[0] for edge in aug_list_A if edge[0] not in match}}
            yield new_matching

    return len(matching)

