def ford_fulkerson(graph, source, sink):
    # Create a residual graph
    residual_graph = defaultdict(lambda: defaultdict(int))

    # Create a distance array to store the shortest path length from the source to each node
    parent = {node: None for node in set(graph)}
    distance = {node: float('inf') for node in set(graph)}

    # Initialize the distance of the source node as 0
    distance[source] = 0

    while True:
        # Find an augmenting path using BFS
        bfs_queue = [(source, [source])]

        while len(bfs_queue) > 0:
            (node, path) = bfs_queue.pop(0)

            # For each neighbor of the current node in the path
            for neighbor, capacity in graph[node].items():
                if parent[neighbor] is None and distance[node] + 1 < distance[neighbor]:
                    # Update the shortest path length
                    distance[neighbor] = distance[node] + 1

                    # Add the neighbor to the BFS queue
                    bfs_queue.append((neighbor, path + [neighbor]))

        # If there's no more augmenting path, break the loop
        if not bfs_queue:
            break

    return distance[sink]

