def max_flow(graph, source, sink):
    parent = [-1] * len(graph)

    def dfs(u, p):
        for v in range(len(graph)):
            if (u, v) not in edge and graph[v][u] > 0:
                if v == p or parent[v] != -1:
                    continue
                parent[v] = u
                yield dfs(v, u)

    max_flow = 0
    while True:
        path = None

        for u in range(len(graph)):
            if parent[u] is not -1 and graph[parent[u]][u]:
                for v in range(u + 1, len(graph)):
                    if graph[v][u] > graph[v][parent[u]]:
                        path = (u, v)
                        break

        if not path:
            break

        s, t = parent[path[0]], path[1]

        while True:
            u, v = s, t
            while v != source:
                graph[u][v], graph[v][u] = graph[v][u], graph[u][v]
                u, v = v, u

            for i in range(len(graph)):
                if graph[i][t]:
                    flow = min(graph[i][t], graph[t][i])

                    while True:
                        j, k = t, source
                        while k != parent[j]:
                            graph[k][j], graph[j][k] -= flow
                            k = parent[k]

                        u, v = s, i
                        while u != s:
                            graph[u][v], graph[v][u] += flow
                            u, v = v, u

            max_flow += flow
            if flow == 0: break

        t, source = path[1], path[0]

    return max_flow

