def max_flow(graph, source, sink):
    # Step 1: Initialize variables
    max_flow = 0

    while True:
        # Find augmenting path using BFS
        parent = bfs(graph, source, sink)

        if not parent:
            break

        # Calculate minimum capacity along the path
        min_capacity = float('inf')
        path_flow = float('inf')
        for s in list(parent.keys()):
            for t in list(parent.keys())[1:]:
                if (s, t) in graph.edges:
                    path_flow = min(path_flow, graph[parent[s]][t].cap)

        # Update the residual capacities along the augmenting path
        v = sink
        while v != source:
            u = parent[v]
            graph[u][v]['flow'] += path_flow
            graph[v][u]['flow'] -= path_flow
            v = parent[v]

    return max_flow

# Function to find BFS augmentation path from source to sink
def bfs(graph, source, sink):
    parent = {}
    queue = [source]
    parent[source] = -1

    while queue:
        u = queue.pop(0)

        for v in graph[u].keys():
            if v == sink and parent[v] != -1:
                return {u: v}
            elif v not in parent or (graph[parent[v]][v]['flow'] + graph[u][v]['cap']) > 0:
                queue.append(v)
                parent[v] = u

    return None

